module top_module(
    input [3:0] obf_D,
    input EN,
    input [1:0] SEL,
    output reg Y
);always @ (SEL or obf_D or EN) begin
    if (EN) begin
        case (SEL)
            2'b00: Y = obf_D[0];
            2'b01: Y = obf_D[1];
            2'b10: Y = obf_D[2];
            2'b11: Y = obf_D[3];
        endcase
    end else begin
        Y = 0;
    end
end

endmodule
